INSERT INTO labs (id, shortname, name, description) VALUES
  ('l1', 'CVIT',  'Center for Visual Information Technology',          'Computer vision, generative models, and medical imaging.'),
  ('l2', 'LTRC',  'Language Technologies Research Centre',             'Natural language processing, computational linguistics, and information retrieval.'),
  ('l3', 'CSTAR', 'Center for Security, Theory & Algorithmic Research','Cryptography, security, and complexity theory.'),
  ('l4', 'SERC',  'Software Engineering Research Center',              'Programming languages, software analysis, and systems.'),
  ('l5', 'RRC',   'Robotics Research Center',                          'Mobile robotics, motion planning, and autonomous navigation.'),
  ('l6', 'SPCRC', 'Signal Processing & Communications Research Center','Communications, audio processing, and biomedical signals.');
INSERT INTO faculty (id, slug, name, bio, lab_id) VALUES
  ('f1',  'karthik-vaidhyanathan', 'Karthik Vaidhyanathan', 'Software architecture, self-adaptive systems, and ML for software engineering. Teaches operating systems and software engineering at IIIT Hyderabad.', 'l4'),
  ('f2',  'manish-shrivastava',    'Manish Shrivastava',    'NLP, machine translation, and low-resource Indian languages. Director of the Language Technologies Research Centre.', 'l2'),
  ('f3',  'cv-jawahar',            'C.V. Jawahar',          'Computer vision, document image analysis, and multimodal learning. Leads CVIT and has supervised over 30 doctoral students.', 'l1'),
  ('f4',  'avinash-sharma',        'Avinash Sharma',        '3D vision, geometry processing, and human shape reconstruction. Focuses on learning-based methods for 3D scene understanding.', 'l1'),
  ('f5',  'vasudeva-varma',        'Vasudeva Varma',        'Information retrieval, text summarization, and social computing. His group works on large-scale text analytics and NLP for Indian languages.', 'l2'),
  ('f6',  'madhava-krishna',       'Madhava Krishna',       'Mobile robotics, autonomous driving, and motion planning. Leads the Robotics Research Center and has pioneered outdoor robot navigation in unstructured terrain.', 'l5'),
  ('f7',  'suresh-purini',         'Suresh Purini',         'Compilers, parallel computing, and high-performance systems. Known for board-based lectures that reward careful note-taking.', 'l4'),
  ('f8',  'kavita-vemuri',         'Kavita Vemuri',         'Cognitive science, neuroaesthetics, and human-computer interaction. Runs an interdisciplinary lab exploring the relationship between perception, emotion, and design.', NULL),
  ('f9',  'cr-bharathi',           'C.R. Bharathi',         'Digital systems and VLSI design.', 'l6'),
  ('f10', 'srinath-naidu',         'Srinath Naidu',         'Embedded systems and microcontroller programming.', 'l6'),
  ('f11', 'ravi-bapna',            'Ravi Bapna',            'History and philosophy of science and technology.', NULL),
  ('f12', 'prashant-pandey',       'Prashant Pandey',       'Probability theory, random processes, and applied mathematics.', NULL),
  ('f13', 'suresh-balaji',         'Suresh Balaji',         'Statistics and mathematical methods for engineering.', NULL),
  ('f14', 'kishore-kothapalli',    'Kishore Kothapalli',    'Algorithmic game theory, mechanism design, and parallel algorithms.', NULL);
INSERT INTO courses (id, code, name, description, type) VALUES
  ('cs3301', 'CS3.301', 'Operating Systems',                  'Processes, scheduling, memory management, file systems, and OS design with hands-on xv6 projects.', 'core'),
  ('cs7401', 'CS7.401', 'Introduction to NLP',                'Fundamentals of natural language processing including text classification, sequence models, and transformers.', 'stream'),
  ('cs5604', 'CS5.604', 'Computer Vision',                    'Image formation, feature extraction, deep learning for vision, and 3D understanding.', 'stream'),
  ('cs1201', 'CS1.201', 'Data Structures',                    'Arrays, linked lists, trees, graphs, hashing, and algorithm analysis.', 'core'),
  ('ec2202', 'EC2.202', 'Digital Systems & Microcontrollers', 'Logic design, sequential circuits, microcontroller architecture, and embedded programming.', 'core'),
  ('hs2103', 'HS2.103', 'History & Philosophy of Science',    'Scientific revolutions, epistemology, and the relationship between science, society, and technology.', 'hs'),
  ('ma3102', 'MA3.102', 'Probability & Random Processes',     'Probability spaces, distributions, expectation, stochastic processes, and engineering applications.', 'math'),
  ('cs6301', 'CS6.301', 'Distributed Systems',                'Consensus, replication, fault tolerance, distributed transactions, and modern systems design.', 'stream'),
  ('cs4301', 'CS4.301', 'Compilers',                          'Lexing, parsing, semantic analysis, intermediate representations, and code generation.', 'stream'),
  ('op3102', 'OP3.102', 'Cognitive Science',                  'Memory, attention, perception, and decision-making through computational and neuroscientific lenses.', 'open'),
  ('bq5102', 'BQ5.102', 'Game Theory & Mechanism Design',     'Strategic interaction, Nash equilibria, auction theory, and mechanism design with applications in CS.', 'bouquet');
