INSERT INTO course_reviews (id, user_id, offering_id, anonymous, difficulty, teaching, grading, content, workload, body) VALUES
  ('r-cs3301-1', 'u1', 'cs3301-m24', false, 4, 5, 3, 5, 4, 'Probably the single most demanding course in the CSE core, and worth every hour. The xv6 projects start gentle but project 4 (virtual memory) will eat your weekend if you don''t start early. Vaidhyanathan sir runs office hours generously and the TAs are excellent. Grading on the final project felt strict — partial credit was minimal — but the lectures are tightly scripted and the slides are usable as standalone notes.'),
  ('r-cs3301-2', 'u_a1', 'cs3301-m24', true, 5, 4, 3, 5, 5, 'If you have not written C in a while, brush up before week 1. The course assumes serious comfort with pointers and gdb. The file system project at the end was the highlight of my semester — got to design layout, journaling, and crash recovery from scratch.'),
  ('r-cs3301-3', 'u2', 'cs3301-s24', false, 4, 5, 4, 4, 4, 'Purini sir''s lectures are the clearest exposition of OS concepts I''ve seen. He works through case studies on the board rather than slides, which takes some getting used to but rewards careful note-taking. Workload is heavy but predictable — five projects, each two weeks.'),
  ('r-cs3301-4', 'u_a1', 'cs3301-s24', true, 4, 4, 3, 4, 4, 'Good course but the autograder for the scheduler project was finicky — multiple students lost marks to timing tolerances that weren''t documented. Worth raising with the instructors if it happens again.'),
  ('r-cs3301-5', 'u3', 'cs3301-m23', false, 4, 4, 4, 5, 4, 'Take this even if it''s not in your stream. The mental model you build for how a kernel actually boots, schedules, and protects memory is hard to acquire any other way. Pair with a friend for projects — debugging concurrency bugs alone at 3am is rough.'),
  ('r-cs3301-6', 'u_a1', 'cs3301-m23', true, 4, 4, 4, 5, 4, 'The reading list (mostly OSTEP and selected papers) is genuinely useful long after the course ends. Don''t skip the optional papers on Linux schedulers — they came up in the final exam.'),
  ('r-cs7401-1', 'u4', 'cs7401-m24', false, 4, 5, 4, 5, 4, 'Best elective I''ve taken at IIIT-H. Shrivastava sir covers both classical and neural NLP without rushing either. The weekly PyTorch assignments build intuition incrementally — you don''t feel lost unless you skip sessions. Final project is open-ended, which is both exciting and stressful.'),
  ('r-cs7401-2', 'u_a1', 'cs7401-m24', true, 3, 5, 4, 5, 3, 'Compared to most ML courses here, this one actually explains the math behind transformers clearly. Assignments are graded fairly and feedback is quick. Highly recommend if you''re even mildly interested in language models.'),
  ('r-cs7401-3', 'u5', 'cs7401-m23', false, 4, 5, 5, 5, 4, 'Took this in my 7th semester and wish I had taken it earlier. The section on low-resource languages and transliteration is something you won''t find in online courses. Grading is generous if your approach is reasonable.'),
  ('r-cs7401-4', 'u_a1', 'cs7401-m23', true, 4, 4, 4, 4, 4, 'The paper reading components are genuinely challenging but rewarding. One suggestion: the project timeline is tight around midsem — start early and scope down aggressively.'),
  ('r-cs7401-5', 'u6', 'cs7401-m22', false, 3, 5, 4, 5, 3, 'One of the few courses where the professor''s research directly informs the curriculum. The section on morphologically rich languages is unique to this class. Prerequisites are light — intro ML is sufficient.'),
  ('r-cs5604-1', 'u7', 'cs5604-s25', false, 4, 4, 4, 5, 4, 'Jawahar sir brings decades of actual CV research into the lectures — you get a perspective that no textbook can replicate. The CNN project in week 8 is where it all clicks. Start assignments the day they''re released, not the day before deadline.'),
  ('r-cs5604-2', 'u_a1', 'cs5604-s25', true, 4, 5, 3, 4, 4, 'The classical part (Harris corners, SIFT, epipolar geometry) is taught rigorously and tests well. The grading rubric on the deep learning project was unclear — some excellent work got lower marks than expected.'),
  ('r-cs5604-3', 'u8', 'cs5604-s24', false, 5, 4, 4, 4, 4, 'Avinash sir''s lectures on 3D geometry are exceptional. The stereo reconstruction project was the most satisfying assignment of my undergrad. Expect to spend serious time debugging matrix operations.'),
  ('r-cs5604-4', 'u_a1', 'cs5604-s24', true, 4, 4, 4, 4, 4, 'Good balance of theory and implementation. PyTorch experience will save you hours. The final project timeline was reasonable and the TAs were responsive on the course channel.'),
  ('r-cs5604-5', 'u9', 'cs5604-s23', false, 4, 4, 4, 5, 4, 'The breadth is impressive — from image formation to segmentation to deep learning in one semester. Exams are fair and based directly on lecture material. The document image analysis component is especially unique.'),
  ('r-cs1201-1', 'u10', 'cs1201-m24', false, 3, 4, 4, 4, 4, 'Solid foundation course. The C++ implementation requirement forces you to understand what''s happening under the hood. Labs are well-structured and the TAs are helpful. Nothing groundbreaking but a necessary building block.'),
  ('r-cs1201-2', 'u_a1', 'cs1201-m24', true, 4, 3, 4, 4, 4, 'Some lecture sections felt rushed — red-black trees and AVL trees were covered in too little time. The assignments compensate though; implementing a self-balancing BST from scratch forces real understanding.'),
  ('r-cs1201-3', 'u11', 'cs1201-s24', false, 3, 5, 4, 4, 3, 'Purini sir makes even the driest topics engaging. The graph algorithms section was handled with elegance I hadn''t seen before. Pacing is good and office hours are never crowded.'),
  ('r-cs1201-4', 'u_a1', 'cs1201-s24', true, 3, 4, 5, 4, 3, 'Grading was transparent and generous — partial credit was actually given, unlike some other core courses. Problem sets are from standard texts (Cormen) which makes self-study easy.'),
  ('r-cs1201-5', 'u12', 'cs1201-m23', false, 4, 4, 4, 4, 4, 'The hash table collision resolution section was the most practical part. Both professors brought different problem-solving styles which actually enriched the course. Recommend pairing with CLRS for deeper understanding.'),
  ('r-ec2202-1', 'u13', 'ec2202-m24', false, 4, 3, 3, 4, 5, 'The hardware labs are genuinely fun but the grading is brutal — one wiring mistake and you lose the whole lab mark. Theory lectures are dense and assume prior ECE background that CSE students often lack.'),
  ('r-ec2202-2', 'u_a1', 'ec2202-m24', true, 5, 2, 3, 3, 5, 'The STM32 microcontroller labs are interesting but the setup documentation is outdated. Spent three hours troubleshooting a toolchain issue that wasn''t in any handout. Course content is relevant but delivery needs work.'),
  ('r-ec2202-3', 'u14', 'ec2202-s24', false, 4, 4, 4, 4, 4, 'The FSM unit was the most well-taught part — clear progression from theory to implementation. Spring offering felt better organized than what I heard about Monsoon. The Cortex-M programming section is genuinely useful for embedded internships.'),
  ('r-ec2202-4', 'u_a1', 'ec2202-m23', true, 4, 3, 3, 4, 4, 'If you''re from CSE and haven''t touched hardware before, budget extra time. The combinational logic section is manageable but the memory-mapped I/O in week 9 assumes understanding of bus protocols that was never explicitly covered.'),
  ('r-hs2103-1', 'u15', 'hs2103-m24', false, 2, 5, 5, 5, 2, 'Genuinely changed how I think about scientific knowledge. The session on Kuhn''s paradigm shifts applied to software engineering was something I didn''t expect from an HS course. Bapna sir''s Socratic teaching style makes every class feel like a conversation.'),
  ('r-hs2103-2', 'u_a1', 'hs2103-m24', true, 2, 5, 5, 4, 2, 'Easiest A on campus but also surprisingly intellectually nourishing. The reading list (Popper, Lakatos, Kuhn, Feyerabend) covers the real philosophical debates, not pop-science summaries. Two essay assignments — both graded generously.'),
  ('r-hs2103-3', 'u16', 'hs2103-s24', false, 3, 5, 4, 5, 3, 'The philosophy of physics section (quantum mechanics epistemology) was the highlight. Spring offering adds a guest lecture from a physics faculty member which is excellent. Attendance matters — participation is part of the grade.'),
  ('r-hs2103-4', 'u_a1', 'hs2103-m23', true, 2, 5, 5, 5, 2, 'The best HS elective available. If you''ve ever wondered how scientific consensus actually forms — beyond the textbook narrative of linear progress — this course answers that. The Feyerabend session alone is worth registering for.'),
  ('r-ma3102-1', 'u17', 'ma3102-m24', false, 5, 3, 3, 4, 4, 'The material is essential for ML and systems work but the teaching style is abstract to a fault. Heavy emphasis on proofs with minimal worked examples in class. You''ll need to supplement with MIT OCW 6.041 or similar. Convergence theorems felt rushed at the end.'),
  ('r-ma3102-2', 'u_a1', 'ma3102-m24', true, 5, 2, 3, 4, 4, 'If you''re planning to do ML research, take this. If you''re not, reconsider. The course assumes real analysis fluency that isn''t explicitly listed as a prerequisite. Homework solutions are not released — this is frustrating when you''re stuck on problem sets.'),
  ('r-ma3102-3', 'u18', 'ma3102-s24', false, 4, 4, 3, 4, 4, 'Spring offering is better structured — the Markov chain section is expanded and the examples come from actual CS applications. The mid-semester exam is the hardest I''ve encountered here; practice old papers religiously.'),
  ('r-ma3102-4', 'u_a1', 'ma3102-s24', true, 4, 3, 3, 4, 4, 'Decent course that suffers from unclear grading criteria. The Poisson process section is the most applicable to real problems. Form study groups early — the problem sets are designed for collaboration even when they don''t say so.'),
  ('r-ma3102-5', 'u19', 'ma3102-m23', false, 5, 3, 3, 4, 4, 'Two professors brings variety but also inconsistency in notation. The convergence in distribution material was the hardest but Balaji sir''s examples from queueing theory made it concrete. Watch the Poisson process section on NPTEL as supplement.'),
  ('r-cs6301-1', 'u20', 'cs6301-m24', false, 4, 5, 4, 5, 5, 'The most intellectually stimulating course in my time here. Implementing Raft from scratch in Go is genuinely hard and genuinely worthwhile. Purini sir walks through the Lamport papers with the kind of care that makes complex ideas feel obvious in retrospect. Budget two weekends per project.'),
  ('r-cs6301-2', 'u_a1', 'cs6301-m24', true, 5, 4, 4, 5, 5, 'The paper reading component is non-negotiable — papers are assigned weekly and you''re expected to discuss them. The Dynamo and Spanner papers changed how I think about tradeoffs in system design. Not a course for passive learners.'),
  ('r-cs6301-3', 'u21', 'cs6301-m23', false, 4, 5, 4, 5, 4, 'The Go project was my first time writing Go and the learning curve added to the workload. Still the most practically relevant course I''ve taken — every distributed system concept here comes up in interviews. Start project 2 (leader election) immediately.'),
  ('r-cs6301-4', 'u_a1', 'cs6301-m23', true, 4, 4, 3, 5, 5, 'Grading is the one weak point — the project rubric is vague and correctness testing is partial. The material and teaching quality are excellent though. Kafka and stream processing section in week 11 is worth the semester alone.'),
  ('r-cs6301-5', 'u22', 'cs6301-m22', false, 4, 5, 4, 5, 5, 'The joint teaching by Purini and Vaidhyanathan was excellent — complementary perspectives on the same problems. The vector clocks and consistent snapshots section had me rethinking assumptions I had about time. Heavy workload but every hour is worth it.'),
  ('r-cs4301-1', 'u23', 'cs4301-s25', false, 4, 4, 4, 5, 5, 'Writing a working compiler is one of the most satisfying engineering experiences you can have in undergrad. The recursive descent parser project in week 4 is where it all comes together. Purini sir''s debugging style — teaching you to reason about the grammar before touching code — is something you carry forward.'),
  ('r-cs4301-2', 'u_a1', 'cs4301-s25', true, 5, 4, 4, 5, 5, 'The optimization passes project is where people either fall in love with the course or hit a wall. Data flow analysis is genuinely subtle. Don''t underestimate the IR design phase — decisions you make in project 2 will haunt or help you in project 4.'),
  ('r-cs4301-3', 'u24', 'cs4301-s24', false, 4, 5, 4, 4, 4, 'Clearer teaching than any PL course I''ve taken online. The lecture on SSA form was a revelation. The C++ codebase you build is messy by the end but looking back at project 1 from project 4 shows you how much you''ve learned.'),
  ('r-cs4301-4', 'u_a1', 'cs4301-s24', true, 4, 4, 4, 4, 5, 'Workload is genuinely high — each project takes a full weekend minimum. The register allocation project is brutal if you''ve never thought about graph coloring. Worth it if you care about how computers actually work.'),
  ('r-cs4301-5', 'u25', 'cs4301-s23', false, 4, 5, 3, 5, 4, 'The final exam was the hardest I''ve written — not because the material was obscure but because it requires combining four different concepts simultaneously. Prepare by writing out the full compilation pipeline from memory. Grading on project 3 felt inconsistent between groups.'),
  ('r-op3102-1', 'u26', 'op3102-m24', false, 2, 5, 4, 5, 3, 'The perfect elective if you''re a CSE student curious about how intelligence works. Vemuri ma''am bridges the gap between AI and cognitive psychology in a way that''s actually actionable. The memory and attention modules will change how you think about your own learning.'),
  ('r-op3102-2', 'u_a1', 'op3102-m24', true, 2, 4, 4, 5, 2, 'Light workload but substantive content. The classic experiments (Stroop, Sperling, Chomsky) are presented with enough depth to actually understand what was surprising about them. Good option if you need an open elective without a heavy time commitment.'),
  ('r-op3102-3', 'u27', 'op3102-s24', false, 3, 5, 5, 4, 3, 'Spring offering includes an extra module on HCI and embodied cognition that made the course even more relevant. The final essay was the most thought I''d put into a non-CS assignment all year. Grading is among the most fair I''ve experienced.'),
  ('r-op3102-4', 'u_a1', 'op3102-m23', true, 2, 5, 4, 4, 2, 'Best open elective I''ve taken. Don''t take it expecting an easy grade trap — the content requires genuine engagement. But if you''re curious about the science of mind, it''s a remarkable 3 credits.'),
  ('r-bq5102-1', 'u28', 'bq5102-m24', false, 4, 5, 4, 5, 3, 'A genuinely unique course at IIIT-H. The auction theory section and its connection to ad markets is something you''ll find immediately applicable if you work in tech. Kothapalli sir presents proofs clearly and makes the math feel inevitable rather than arbitrary.'),
  ('r-bq5102-2', 'u_a1', 'bq5102-m24', true, 4, 4, 4, 4, 3, 'The social choice section (Arrow''s impossibility theorem) was mind-bending. Nash equilibria and mixed strategies take time to internalize — the problem sets are well designed to build that intuition gradually. Lighter workload than most 4-credit courses.'),
  ('r-bq5102-3', 'u29', 'bq5102-s24', false, 3, 5, 5, 5, 3, 'If you''ve done any algorithmic competitive programming, the mechanism design section feels like a natural extension. The VCG mechanism proof is the most elegant argument I''ve seen in a course here. Grading is fair with detailed written feedback.'),
  ('r-bq5102-4', 'u_a1', 'bq5102-m23', true, 4, 4, 4, 5, 4, 'The connection between game theory and CS — approximation algorithms, online algorithms, protocol design — is explored seriously here, not just mentioned in passing. Recommended for anyone interested in theory.');
INSERT INTO advisor_reviews (id, user_id, faculty_id, anonymous, research, availability, mentorship, support, workload, body) VALUES
  ('ar-f1-1', 'u_a1', 'f1', false, 5, 5, 5, 4, 4, 'Joined SERC for an honours thesis on self-adaptive ML systems and Karthik sir was everything I had hoped for. Weekly 1:1s without fail, never cancelled. He pushed me to submit a position paper to an ICSE workshop in my first semester — I wasn''t ready but the process of trying taught me more than a year of coursework. Reads drafts carefully and gives targeted feedback rather than vague notes. Very hands-off on day-to-day execution but clear on direction and expectations.'),
  ('ar-f1-2', 'u_b1', 'f1', true, 4, 5, 5, 5, 3, 'Best part: responds to messages within a few hours, even on weekends, but never expects the same from students. He is very explicit about this — early on he said ''I work weekends, you should not feel obligated to''. Workload is reasonable if you communicate scope upfront and don''t let ambiguity pile up. Research taste is excellent — he steered me away from an incremental idea toward something genuinely interesting.'),
  ('ar-f1-3', 'u_a3', 'f1', false, 5, 4, 4, 4, 4, 'Strong research taste and willing to say ''this problem isn''t interesting enough'' clearly and early. Be ready to defend your framing — he''ll push back on the problem statement before he lets you build solutions. Once you have a direction he agrees with, support is excellent. He connected me with collaborators at IITB which led to a co-first-authorship. Workload is proportional to what you commit to — no surprise deadlines.'),
  ('ar-f2-1', 'u_b1', 'f2', false, 5, 5, 5, 5, 4, 'Working with Manish sir on my thesis on code-switching in social media text was remarkable. He has deep expertise in Indian language NLP and could immediately identify which papers were foundational vs. derivative. Meeting frequency is excellent — bi-weekly at minimum, more when a deadline was approaching. He genuinely cares whether students get papers out at good venues, not just any venues.'),
  ('ar-f2-2', 'u_a1', 'f2', true, 5, 4, 5, 5, 4, 'The breadth of Manish sir''s reading is outstanding — he suggested relevant papers I would never have found through standard searches. He has a strong network in the ACL and EMNLP communities which translated to useful reviewer feedback on my submissions. One thing to note: he runs a large lab and managing your own schedule matters. Students who are self-directed thrive; those who need frequent check-ins should set up a recurring slot explicitly.'),
  ('ar-f2-3', 'u_b3', 'f2', false, 5, 4, 4, 4, 4, 'My experience was very positive overall. He gave me genuine ownership of my research direction from month two, which felt both exciting and daunting. The support when things weren''t working was strong — he didn''t pressure me to produce results on a fixed timeline. His feedback on writing is excellent and he''s willing to iterate many times on a paper draft before submission.'),
  ('ar-f3-1', 'u_c1', 'f3', false, 5, 4, 4, 4, 4, 'Jawahar sir''s advice is worth waiting for — he''s busy and availability is limited, but when you do get his attention it is very high quality. He has strong opinions about what constitutes interesting research and won''t let you pursue something incremental. My PhD is in document analysis and the lab infrastructure — datasets, GPU clusters, connections to industry — is unmatched. You need to be independently motivated because he is not a hand-holding advisor.'),
  ('ar-f3-2', 'u_a1', 'f3', true, 5, 3, 5, 4, 4, 'Three years in, I appreciate CVIT''s infrastructure more than I did at the start — access to large compute, real annotated datasets, and visiting researchers is hard to replicate elsewhere. Jawahar sir''s feedback on results is sharp: he focuses on whether the story is convincing, not just whether numbers are high. Availability is the honest weakness — try to get time at lab reading groups, that''s often the most productive interaction.'),
  ('ar-f3-3', 'u_c3', 'f3', false, 5, 4, 4, 5, 5, 'My experience at CVIT under Jawahar sir has been one of steep learning, good pressure, and eventual satisfaction. He does not micromanage; if that sounds like your preferred style this is the right fit. The lab culture of publishing at top venues means mediocre results won''t get support for submission, which is both a constraint and a quality filter. He was instrumental in getting me an internship at a top research lab which changed my trajectory.'),
  ('ar-f4-1', 'u_a1', 'f4', true, 4, 4, 4, 4, 4, 'Avinash sir is a hands-on advisor for 3D vision work — he stays current with the latest papers and our weekly meetings involve detailed discussion of both experiments and related work. Availability is reasonable for a junior faculty member running a growing lab. Workload expectations are high but predictable; no surprises. He is direct about what results are publishable and what still needs work.'),
  ('ar-f4-2', 'u_d2', 'f4', false, 5, 4, 4, 4, 4, 'Working on human shape reconstruction under Avinash sir has been engaging. His research taste in 3D computer vision is excellent and he has a clear sense for which venues are worth targeting. He takes mentorship seriously — spent multiple sessions helping me understand reviewer feedback from a rejection, which improved both the paper and my understanding of the field''s norms.'),
  ('ar-f4-3', 'u_b1', 'f4', true, 4, 4, 5, 4, 4, 'Avinash sir is accessible and willing to debate research ideas in detail, which I appreciate — he doesn''t just direct, he engages. The lab is at an early growth stage so you do get more individual attention than in the larger CVIT labs. He could improve on support for non-technical career development, but for research mentorship it is strong.'),
  ('ar-f5-1', 'u_e1', 'f5', false, 5, 4, 4, 4, 4, 'Vasudeva sir runs a large group and expects students to have initiative. He is very well-connected in the IR and NLP community, and that translated to paper introductions and internship recommendations I wouldn''t have gotten otherwise. Research taste is refined — he knows what problems matter and why. Availability requires effort: you need to schedule explicitly and follow through. He''s not going to track you down.'),
  ('ar-f5-2', 'u_a1', 'f5', true, 4, 4, 5, 5, 4, 'The depth of Vasudeva sir''s network in industry and academia is a tangible research asset. He has good judgment about which problems are interesting to the community vs. locally interesting, which helped me avoid spending six months on a dead-end direction. Feedback on writing is excellent and he engages seriously with student ideas rather than just providing top-down direction.'),
  ('ar-f5-3', 'u_e3', 'f5', false, 5, 5, 4, 4, 4, 'My experience has been very positive. He is realistic about the academic job market and research pace, which some students find deflating but I found genuinely helpful for calibrating expectations. His involvement in SIGIR, CIKM, and ACL communities means reviewer pools and submission deadlines are very clearly understood. Good lab culture and supportive peers.'),
  ('ar-f6-1', 'u_f1', 'f6', false, 5, 3, 4, 4, 4, 'Madhava sir is a leading figure in Indian robotics and the research ambition at RRC shows. For students doing outdoor mobile robotics the infrastructure is exceptional — actual platforms, outdoor test sites, and the whole stack. Availability is limited partly due to his leadership responsibilities, but he makes up for it by being fully engaged in lab meetings and design reviews. Expect a high workload on systems projects.'),
  ('ar-f6-2', 'u_a1', 'f6', true, 5, 4, 4, 4, 5, 'RRC is well-funded and the resources for robotics work are excellent. Madhava sir has a very high bar for publication — he won''t submit work that doesn''t have a clear technical contribution and strong evaluation. That means you may spend longer on a paper, but the end result holds up to scrutiny. I found his directness about what wasn''t working to be genuinely useful even when it was hard to hear.'),
  ('ar-f6-3', 'u_f3', 'f6', false, 5, 3, 4, 4, 5, 'Strong research instincts and very deep technical knowledge of robotics, especially planning and perception. He is not always available for unplanned questions — you need to be patient and use lab meetings effectively. Workload is real: fieldwork, long training runs, and debugging on hardware takes time. If you are excited about autonomous vehicles or field robotics this is the best lab in India to do it.'),
  ('ar-f7-1', 'u_g1', 'f7', false, 4, 4, 4, 4, 4, 'Suresh sir has a very clean research taste in compilers and parallel systems — he focuses on problems where the solution can be evaluated rigorously. Our weekly meetings are productive and he gives detailed feedback on experimental setup and analysis. He thinks through problems clearly and the way he reasons about them is easy to observe. Workload is high but he doesn''t add scope mid-project without discussion.'),
  ('ar-f7-2', 'u_a1', 'f7', true, 4, 5, 4, 4, 4, 'Very available and responds quickly. His expertise in parallelism and program analysis is deep and he brings a practical angle — asks ''what system does this run on, what benchmark should we use'' early rather than only worrying about theory. Good support network in the lab with older PhD students who are generous with their time.'),
  ('ar-f7-3', 'u_g3', 'f7', false, 5, 4, 5, 4, 4, 'I did my honours project under Suresh sir and it was one of the better academic decisions of my undergrad. He has high standards for evaluation methodology which initially felt restrictive but made the eventual paper much stronger. He connected me with collaborators at IIT Madras which led to a journal extension. Straight-talking about results — if your numbers don''t hold up he will say so immediately.'),
  ('ar-f8-1', 'u_h1', 'f8', false, 5, 5, 5, 5, 4, 'Kavita ma''am is the best advisor I have had in any academic setting. She is deeply invested in student growth beyond research — proactively connected me with industry researchers, provided career advice, and gave me genuine leadership responsibilities in the lab. The research on neuroaesthetics is genuinely interdisciplinary and requires reading across cognitive science, neuroscience, and HCI. She models careful thinking across all three.'),
  ('ar-f8-2', 'u_a1', 'f8', true, 4, 5, 4, 4, 3, 'Workload expectations are very reasonable — she distinguishes between research work and busywork and actively protects student time from the latter. Availability is excellent, meetings are never rushed. The only note is that the lab is smaller and less infrastructure-heavy than the large CS labs, so if you need large-scale compute you may need to arrange it independently or collaborate with CVIT.'),
  ('ar-f8-3', 'u_h3', 'f8', false, 4, 5, 5, 5, 4, 'My experience has been outstanding. Kavita ma''am has a gift for connecting ideas across fields — she regularly introduces cognitive science literature that reframes how I think about HCI problems I am working on. The mentorship is holistic: she thinks about the student as a researcher and a person. She wrote a very strong recommendation letter for my PhD applications abroad and was very thoughtful in tailoring it.');
